218: // DeleteStateByRuleUID removes the rule instances from cache and instanceStore.
219: func (st *Manager) DeleteStateByRuleUID(ctx context.Context, ruleKey ngModels.AlertRuleKeyWithGroup, reason string) []StateTransition {
220: 	logger := st.log.FromContext(ctx)
221: 	logger.Debug("Resetting state of the rule")
222: 
223: 	states := st.ForgetStateByRuleUID(ctx, ruleKey)
224: 
225: 	if len(states) == 0 {
226: 		return nil
227: 	}
228: 
229: 	now := st.clock.Now()
230: 	transitions := make([]StateTransition, 0, len(states))
231: 	for _, s := range states {
232: 		oldState := s.State
233: 		oldReason := s.StateReason
234: 		startsAt := s.StartsAt
235: 		if s.State != eval.Normal {
236: 			startsAt = now
237: 		}
238: 		s.SetNormal(reason, startsAt, now)
239: 		// By setting ResolvedAt we trigger the scheduler to send a resolved notification to the Alertmanager.
240: 		if s.ShouldBeResolved(oldState) {
241: 			s.ResolvedAt = &now
242: 		} else {
243: 			s.ResolvedAt = nil
244: 		}
245: 		s.LastEvaluationTime = now
246: 		s.Values = map[string]float64{}
247: 		transitions = append(transitions, StateTransition{
248: 			State:               s,
249: 			PreviousState:       oldState,
250: 			PreviousStateReason: oldReason,
251: 		})
252: 	}
253: 
254: 	if st.instanceStore != nil {
255: 		err := st.instanceStore.DeleteAlertInstancesByRule(ctx, ruleKey)
256: 		if err != nil {
257: 			logger.Error("Failed to delete states that belong to a rule from database", "error", err)
258: 		}
259: 	}
260: 
261: 	logger.Info("Rules state was reset", "states", len(states))
262: 
263: 	return transitions
264: }
