273: // ResetStateByRuleUID removes the rule instances from cache and instanceStore and saves state history. If the state
274: // history has to be saved, rule must not be nil.
275: func (st *Manager) ResetStateByRuleUID(ctx context.Context, rule *ngModels.AlertRule, reason string) []StateTransition {
276: 	if rule == nil {
277: 		return nil
278: 	}
279: 
280: 	ruleKey := rule.GetKeyWithGroup()
281: 	transitions := st.DeleteStateByRuleUID(ctx, ruleKey, reason)
282: 
283: 	if st.historian == nil || len(transitions) == 0 {
284: 		return transitions
285: 	}
286: 
287: 	ruleMeta := history_model.NewRuleMeta(rule, st.log)
288: 	errCh := st.historian.Record(ctx, ruleMeta, transitions)
289: 	go func() {
290: 		err := <-errCh
291: 		if err != nil {
292: 			st.log.FromContext(ctx).Error("Error updating historian state reset transitions", append(ruleKey.LogContext(), "reason", reason, "error", err)...)
293: 		}
294: 	}()
295: 	return transitions
296: }
