298: // ProcessEvalResults updates the current states that belong to a rule with the evaluation results.
299: // if extraLabels is not empty, those labels will be added to every state. The extraLabels take precedence over rule labels and result labels
300: // This will update the states in cache/store and return the state transitions that need to be sent to the alertmanager.
301: func (st *Manager) ProcessEvalResults(
302: 	ctx context.Context,
303: 	evaluatedAt time.Time,
304: 	alertRule *ngModels.AlertRule,
305: 	results eval.Results,
306: 	extraLabels data.Labels,
307: 	send Sender,
308: ) StateTransitions {
309: 	utcTick := evaluatedAt.UTC().Format(time.RFC3339Nano)
310: 	ctx, span := st.tracer.Start(ctx, "alert rule state calculation", trace.WithAttributes(
311: 		attribute.String("rule_uid", alertRule.UID),
312: 		attribute.Int64("org_id", alertRule.OrgID),
313: 		attribute.Int64("rule_version", alertRule.Version),
314: 		attribute.String("tick", utcTick),
315: 		attribute.Int("results", len(results))))
316: 	defer span.End()
317: 
318: 	logger := st.log.FromContext(ctx)
319: 
320: 	// lazy evaluation of takeImage only once and only if it is requested.
321: 	var fn takeImageFn
322: 	{
323: 		var image *ngModels.Image
324: 		var imageTaken bool
325: 		fn = func(reason string) *ngModels.Image {
326: 			if imageTaken {
327: 				return image
328: 			}
329: 			logger.Debug("Taking image", "dashboard", alertRule.GetDashboardUID(), "panel", alertRule.GetPanelID(), "reason", reason)
330: 			img, err := takeImage(ctx, st.images, alertRule)
331: 			imageTaken = true
332: 			if err != nil {
333: 				logger.Warn("Failed to take an image",
334: 					"dashboard", alertRule.GetDashboardUID(),
335: 					"panel", alertRule.GetPanelID(), "reason", reason,
336: 					"error", err)
337: 				return nil
338: 			}
339: 			image = img
340: 			return image
341: 		}
342: 	}
343: 
344: 	logger.Debug("State manager processing evaluation results", "resultCount", len(results))
345: 	states := st.setNextStateForRule(ctx, alertRule, results, extraLabels, logger, fn, evaluatedAt)
346: 
347: 	missingSeriesStates, staleCount := st.processMissingSeriesStates(logger, evaluatedAt, alertRule, fn)
348: 	span.AddEvent("results processed", trace.WithAttributes(
349: 		attribute.Int("state_transitions", len(states)),
350: 		attribute.Int("stale_states", staleCount),
351: 	))
352: 
353: 	allChanges := StateTransitions(append(states, missingSeriesStates...))
354: 
355: 	// It's important that this is done *before* we sync the states to the persister. Otherwise, we will not persist
356: 	// the LastSentAt field to the store.
357: 	var statesToSend StateTransitions
358: 	if send != nil {
359: 		statesToSend = st.updateLastSentAt(allChanges, evaluatedAt)
360: 	}
361: 
362: 	st.persister.Sync(ctx, span, alertRule.GetKeyWithGroup(), allChanges)
363: 	if st.historian != nil {
364: 		st.historian.Record(ctx, history_model.NewRuleMeta(alertRule, logger), allChanges)
365: 	}
366: 
367: 	// Optional callback intended for sending the states to an alertmanager.
368: 	// Some uses ,such as backtesting or the testing api, do not send.
369: 	if send != nil {
370: 		send(ctx, statesToSend)
371: 	}
372: 
373: 	return allChanges
374: }
