376: // updateLastSentAt returns the subset StateTransitions that need sending and updates their LastSentAt field.
377: // Note: This is not idempotent, running this twice can (and usually will) return different results.
378: func (st *Manager) updateLastSentAt(states StateTransitions, evaluatedAt time.Time) StateTransitions {
379: 	var result StateTransitions
380: 	for _, t := range states {
381: 		if t.NeedsSending(evaluatedAt, st.ResendDelay, st.ResolvedRetention) {
382: 			t.LastSentAt = &evaluatedAt
383: 			result = append(result, t)
384: 		}
385: 	}
386: 	return result
387: }
