236: func (d *AlertsRouter) alertmanagersFromDatasources(orgID int64) ([]ExternalAMcfg, error) {
237: 	// We might have alertmanager datasources that are acting as external
238: 	// alertmanager, let's fetch them.
239: 	query := &datasources.GetDataSourcesByTypeQuery{
240: 		OrgID: orgID,
241: 		Type:  datasources.DS_ALERTMANAGER,
242: 	}
243: 	ctx, cancel := context.WithTimeout(context.Background(), time.Second*5)
244: 	defer cancel()
245: 	dataSources, err := d.datasourceService.GetDataSourcesByType(ctx, query)
246: 	if err != nil {
247: 		return nil, fmt.Errorf("failed to fetch datasources for org: %w", err)
248: 	}
249: 
250: 	alertmanagers := make([]ExternalAMcfg, 0, len(dataSources))
251: 
252: 	for _, ds := range dataSources {
253: 		if !ds.JsonData.Get(definitions.HandleGrafanaManagedAlerts).MustBool(false) {
254: 			continue
255: 		}
256: 
257: 		cfg, err := d.datasourceToExternalAMcfg(ds)
258: 		if err != nil {
259: 			d.logger.Error("Failed to convert datasource to external alertmanager config",
260: 				"org", ds.OrgID,
261: 				"uid", ds.UID,
262: 				"error", err)
263: 			continue
264: 		}
265: 
266: 		alertmanagers = append(alertmanagers, cfg)
267: 	}
268: 
269: 	return alertmanagers, nil
270: }
