272: // datasourceToExternalAMcfg converts a datasource to an ExternalAMcfg.
273: func (d *AlertsRouter) datasourceToExternalAMcfg(ds *datasources.DataSource) (ExternalAMcfg, error) {
274: 	amURL, err := d.buildExternalURL(ds)
275: 	if err != nil {
276: 		return ExternalAMcfg{}, fmt.Errorf("failed to build external alertmanager URL: %w", err)
277: 	}
278: 
279: 	ctx, cancel := context.WithTimeout(context.Background(), time.Second*10)
280: 	headers, err := d.datasourceService.CustomHeaders(ctx, ds)
281: 	cancel()
282: 	if err != nil {
283: 		return ExternalAMcfg{}, fmt.Errorf("failed to get custom headers: %w", err)
284: 	}
285: 
286: 	insecureSkipVerify := false
287: 
288: 	var tlsAuthEnabled bool
289: 	if ds.JsonData != nil {
290: 		insecureSkipVerify = ds.JsonData.Get("tlsSkipVerify").MustBool(false)
291: 		tlsAuthEnabled = ds.JsonData.Get("tlsAuth").MustBool(false)
292: 	}
293: 
294: 	var tlsClientCert, tlsClientKey string
295: 	if tlsAuthEnabled {
296: 		if ds.SecureJsonData == nil {
297: 			return ExternalAMcfg{}, errors.New("tlsAuth is enabled but TLS client certificate and key are not configured")
298: 		}
299: 
300: 		tlsClientKey = d.secretService.GetDecryptedValue(context.Background(), ds.SecureJsonData, "tlsClientKey", "")
301: 		tlsClientCert = d.secretService.GetDecryptedValue(context.Background(), ds.SecureJsonData, "tlsClientCert", "")
302: 
303: 		if tlsClientCert == "" || tlsClientKey == "" {
304: 			return ExternalAMcfg{}, errors.New("tlsAuth is enabled but TLS client certificate or key is empty")
305: 		}
306: 	}
307: 
308: 	return ExternalAMcfg{
309: 		URL:                amURL,
310: 		Headers:            headers,
311: 		InsecureSkipVerify: insecureSkipVerify,
312: 		TLSClientCert:      tlsClientCert,
313: 		TLSClientKey:       tlsClientKey,
314: 	}, nil
315: }
