317: func (d *AlertsRouter) buildExternalURL(ds *datasources.DataSource) (string, error) {
318: 	// We re-use the same parsing logic as the datasource to make sure it matches whatever output the user received
319: 	// when doing the healthcheck.
320: 	parsed, err := datasource.ValidateURL(datasources.DS_ALERTMANAGER, ds.URL)
321: 	if err != nil {
322: 		return "", fmt.Errorf("failed to parse alertmanager datasource url: %w", err)
323: 	}
324: 
325: 	// If this is a Mimir or Cortex implementation, the Alert API is under a different path than config API
326: 	if ds.JsonData != nil {
327: 		impl := ds.JsonData.Get("implementation").MustString("")
328: 		switch impl {
329: 		case "mimir", "cortex":
330: 			if parsed.Path == "" {
331: 				parsed.Path = "/"
332: 			}
333: 			lastSegment := path.Base(parsed.Path)
334: 			if lastSegment != "alertmanager" {
335: 				parsed = parsed.JoinPath("/alertmanager")
336: 			}
337: 		default:
338: 		}
339: 	}
340: 
341: 	// If basic auth is enabled we need to build the url with basic auth baked in.
342: 	if ds.BasicAuth {
343: 		password := d.secretService.GetDecryptedValue(context.Background(), ds.SecureJsonData, "basicAuthPassword", "")
344: 		if password == "" {
345: 			return "", fmt.Errorf("basic auth enabled but no password set")
346: 		}
347: 		parsed.User = url.UserPassword(ds.BasicAuthUser, password)
348: 	}
349: 
350: 	return parsed.String(), nil
