353: func (d *AlertsRouter) Send(ctx context.Context, key models.AlertRuleKey, alerts definitions.PostableAlerts) {
354: 	logger := d.logger.New(key.LogContext()...)
355: 	if len(alerts.PostableAlerts) == 0 {
356: 		logger.Info("No alerts to notify about")
357: 		return
358: 	}
359: 	// Send alerts to local notifier if they need to be handled internally
360: 	// or if no external AMs have been discovered yet.
361: 	d.adminConfigMtx.RLock()
362: 	defer d.adminConfigMtx.RUnlock()
