364: 	if d.sendAlertsTo[key.OrgID] == models.ExternalAlertmanagers && len(d.alertmanagersFor(key.OrgID)) > 0 {
365: 		logger.Debug("All alerts for the given org should be routed to external notifiers only. skipping the internal notifier.")
366: 	} else {
367: 		logger.Info("Sending alerts to local notifier", "count", len(alerts.PostableAlerts))
368: 		n, err := d.multiOrgNotifier.AlertmanagerFor(key.OrgID)
369: 		if err == nil {
370: 			localNotifierExist = true
371: 			if err := n.PutAlerts(ctx, alerts); err != nil {
372: 				logger.Error("Failed to put alerts in the local notifier", "count", len(alerts.PostableAlerts), "error", err)
373: 			}
374: 			if d.broadcastAlerts {
375: 				d.multiOrgNotifier.BroadcastAlerts(key.OrgID, alerts)
376: 			}
377: 		} else {
378: 			if errors.Is(err, notifier.ErrNoAlertmanagerForOrg) {
379: 				logger.Debug("Local notifier was not found")
380: 			} else {
381: 				logger.Error("Local notifier is not available", "error", err)
382: 			}
383: 		}
384: 	}
385: 
386: 	// Send alerts to external Alertmanager(s) if we have a sender for this organization
387: 	// and alerts are not being handled just internally.
388: 	s, ok := d.externalAlertmanagers[key.OrgID]
389: 	if ok && d.sendAlertsTo[key.OrgID] != models.InternalAlertmanager {
390: 		logger.Info("Sending alerts to external notifier", "count", len(alerts.PostableAlerts))
391: 		s.SendAlerts(alerts)
