427: // Run starts regular updates of the configuration.
428: func (d *AlertsRouter) Run(ctx context.Context) error {
429: 	for {
430: 		select {
431: 		case <-time.After(d.adminConfigPollInterval):
432: 			if err := d.SyncAndApplyConfigFromDatabase(ctx); err != nil {
433: 				d.logger.Error("Unable to sync admin configuration", "error", err)
434: 			}
435: 		case <-ctx.Done():
436: 			// Stop sending alerts to all external Alertmanager(s).
437: 			d.adminConfigMtx.Lock()
438: 			for orgID, s := range d.externalAlertmanagers {
439: 				delete(d.externalAlertmanagers, orgID) // delete before we stop to make sure we don't accept any more alerts.
440: 				s.Stop()
441: 			}
442: 			d.adminConfigMtx.Unlock()
443: 
444: 			return nil
445: 		}
446: 	}
447: }
