28: var logger = log.New("ngalert.eval")
29: 
30: type EvaluatorFactory interface {
31: 	// Create builds an evaluator pipeline ready to evaluate a rule's query
32: 	Create(ctx EvaluationContext, condition models.Condition) (ConditionEvaluator, error)
33: }
34: 
35: //go:generate mockery --name ConditionEvaluator --structname ConditionEvaluatorMock --with-expecter --output eval_mocks --outpkg eval_mocks
36: type ConditionEvaluator interface {
37: 	// EvaluateRaw evaluates the condition and returns raw backend response backend.QueryDataResponse
38: 	EvaluateRaw(ctx context.Context, now time.Time) (resp *backend.QueryDataResponse, err error)
39: 	// Evaluate evaluates the condition and converts the response to Results
40: 	Evaluate(ctx context.Context, now time.Time) (Results, error)
41: }
42: 
43: type expressionExecutor interface {
44: 	ExecutePipeline(ctx context.Context, now time.Time, pipeline expr.DataPipeline) (*backend.QueryDataResponse, error)
45: }
46: 
47: type expressionBuilder interface {
48: 	expressionExecutor
49: 	BuildPipeline(ctx context.Context, req *expr.Request) (expr.DataPipeline, error)
50: }
51: 
52: type conditionEvaluator struct {
53: 	pipeline          expr.DataPipeline
54: 	expressionService expressionExecutor
55: 	condition         models.Condition
56: 	evalTimeout       time.Duration
57: 	evalResultLimit   int
58: }
59: 
60: func (r *conditionEvaluator) EvaluateRaw(ctx context.Context, now time.Time) (resp *backend.QueryDataResponse, err error) {
61: 	defer func() {
62: 		if e := recover(); e != nil {
63: 			logger.FromContext(ctx).Error("Alert rule panic", "error", e, "stack", string(debug.Stack()))
64: 			panicErr := fmt.Errorf("alert rule panic; please check the logs for the full stack")
65: 			if err != nil {
66: 				err = fmt.Errorf("queries and expressions execution failed: %w; %v", err, panicErr.Error())
67: 			} else {
68: 				err = panicErr
69: 			}
70: 		}
71: 	}()
72: 
73: 	execCtx := ctx
74: 	if r.evalTimeout >= 0 {
75: 		timeoutCtx, cancel := context.WithTimeout(ctx, r.evalTimeout)
76: 		defer cancel()
77: 		execCtx = timeoutCtx
78: 	}
79: 	logger.FromContext(ctx).Debug("Executing pipeline", "commands", strings.Join(r.pipeline.GetCommandTypes(), ","), "datasources", strings.Join(r.pipeline.GetDatasourceTypes(), ","))
80: 	result, err := r.expressionService.ExecutePipeline(execCtx, now, r.pipeline)
81: 
82: 	// Check if the result of the condition evaluation is too large
83: 	if err == nil && result != nil && r.evalResultLimit > 0 {
84: 		conditionResultLength := 0
85: 		if conditionResponse, ok := result.Responses[r.condition.Condition]; ok {
86: 			conditionResultLength = len(conditionResponse.Frames)
87: 		}
88: 		if conditionResultLength > r.evalResultLimit {
89: 			logger.FromContext(ctx).Error("Query evaluation returned too many results", "limit", r.evalResultLimit, "actual", conditionResultLength)
90: 			return nil, fmt.Errorf("query evaluation returned too many results: %d (limit: %d)", conditionResultLength, r.evalResultLimit)
91: 		}
92: 	}
93: 
94: 	return result, err
95: }
96: 
97: // Evaluate evaluates the condition and converts the response to Results
98: func (r *conditionEvaluator) Evaluate(ctx context.Context, scheduledAt time.Time) (Results, error) {
99: 	start := time.Now()
100: 	response, err := r.EvaluateRaw(ctx, scheduledAt)
101: 	if err != nil {
102: 		return nil, err
103: 	}
104: 	return EvaluateAlert(response, r.condition, scheduledAt, start), nil
105: }
106: 
107: type evaluatorImpl struct {
108: 	evaluationTimeout     time.Duration
109: 	evaluationResultLimit int
110: 	dataSourceCache       datasources.CacheService
111: 	expressionService     expressionBuilder
112: }
113: 
114: func NewEvaluatorFactory(
115: 	cfg setting.UnifiedAlertingSettings,
116: 	datasourceCache datasources.CacheService,
117: 	expressionService *expr.Service,
118: ) EvaluatorFactory {
119: 	return &evaluatorImpl{
120: 		evaluationTimeout:     cfg.EvaluationTimeout,
121: 		evaluationResultLimit: cfg.EvaluationResultLimit,
122: 		dataSourceCache:       datasourceCache,
123: 		expressionService:     expressionService,
124: 	}
125: }
126: 
127: // EvaluateAlert takes the results of an executed query and evaluates it as an alert rule, returning alert states that the query produces.
128: func EvaluateAlert(queryResponse *backend.QueryDataResponse, condition models.Condition, scheduledAt time.Time, evalStart time.Time) Results {
129: 	execResults := queryDataResponseToExecutionResults(condition, queryResponse)
130: 	return evaluateExecutionResult(execResults, scheduledAt, evalStart)
131: }
132: 
133: // invalidEvalResultFormatError is an error for invalid format of the alert definition evaluation results.
134: type invalidEvalResultFormatError struct {
135: 	refID  string
136: 	reason string
137: 	err    error
138: }
139: 
140: func (e *invalidEvalResultFormatError) Error() string {
141: 	s := fmt.Sprintf("invalid format of evaluation results for the alert definition %s: %s", e.refID, e.reason)
142: 	if e.err != nil {
143: 		s = fmt.Sprintf("%s: %s", s, e.err.Error())
144: 	}
145: 	return s
146: }
147: 
148: func (e *invalidEvalResultFormatError) Unwrap() error {
149: 	return e.err
150: }
